import xml.etree.ElementTree as ET
from xml.etree.ElementTree import ParseError
from xml.schema import XMLSchema, XMLValidationReport

def validate_and_read_xml(xml_file):
    schema = XMLSchema(ET.parse('your_xsd_file_path'))
    try:
        tree = ET.parse(xml_file)
        schema.validate(tree)
        return ET.tostring(tree, encoding='utf-8', method='xml')
    except ParseError as e:
        print("Error parsing XML:", e)
        return None
    except ValidationError as ve:
        report = XMLValidationReport(ve)
        print("Validation errors:", [(node.sourceline, node.sourcerow, msg) for msg, node in report.error_list])
        return None